// MARK: - Resize to Fit Image

func resizeToFitImage(_ size: NSSize, center: Bool = true) {
    guard let window,
          let screen = window.screen,
          !window.styleMask.contains(.fullScreen) else { return }
    let visibleFrame = screen.visibleFrame
    let maxSize = visibleFrame.size
    let requestedSize = NSSize(
        width: min(size.width, maxSize.width),
        height: min(size.height, maxSize.height)

// MARK: - Cmd + Scroll Wheel Zoom

private func handleCmdScrollZoom(with event: NSEvent) {
    let delta = event.scrollingDeltaY
    guard abs(delta) > 0.01 else { return }

    // Zoom 方向：deltaY > 0 = 放大，deltaY < 0 = 縮小
    // 不跟隨 Natural Scrolling 反轉（主流慣例：scroll up = zoom in）
    let sensitivity: CGFloat = event.hasPreciseScrollingDeltas ? 0.003 : 0.08
    let newMag = magnification + delta * sensitivity
    let effectiveMin = max(minMagnification, scrollDelegate?.minimumMagnification(for: self) ?? effectiveMinMagnification())
    let clamped = max(effectiveMin, min(maxMagnification, newMag))

    // 以可預測的視窗中心為 anchor（避免 contentInsets 暫時被重置時漂移到左側）
    let center = zoomAnchorPoint()
    setMagnificationPreservingInsets(clamped, centeredAt: center)

    // 通知 delegate（與 pinch zoom 一致）
    scrollDelegate?.scrollViewMagnificationDidChange(
        self, magnification: magnification, gesturePhase: event.phase
    )
}

// MARK: - Option + Scroll Fast Navigation (Phase 3)

private func handleOptionScrollNav(with event: NSEvent) {
    let isTrackpad = event.phase != [] || event.momentumPhase != []
    let isMomentum = event.momentumPhase != []

    // Trackpad: 新手勢開始時重置累積器
    if event.phase == .began {
        optionScrollAccumulator.resetForNewGesture()
        resetEdgeState()
    }

    // Mouse: 沒有 .began phase，改用時間間隔偵測新手勢
    if !isTrackpad {
        let now = CFAbsoluteTimeGetCurrent()
        if now - lastOptionScrollTime > Constants.optionScrollMouseResetInterval {
            optionScrollAccumulator.resetForNewGesture()
            resetEdgeState()
        }
        lastOptionScrollTime = now
    }

    // Natural Scrolling 方向校正（與 page-turn 邏輯一致）
    let isNatural = event.isDirectionInvertedFromDevice
    let rawDelta = event.scrollingDeltaY
    let correctedDelta: CGFloat
    if isNatural {
        correctedDelta = -rawDelta
    } else {
        correctedDelta = rawDelta
    }

    // 滑鼠 delta 極小（~0.1-1.0），需放大至 threshold 量級
    let scaledDelta = isTrackpad ? correctedDelta
        : correctedDelta * Constants.optionScrollMouseSensitivity

    let steps = optionScrollAccumulator.accumulate(
        delta: scaledDelta,
        isTrackpad: isTrackpad,
        isMomentum: isMomentum
    )

    guard steps != 0 else { return }

    // 限制每次最多導航 1 張，確保逐張切換可見（避免跳躍）
    scrollDelegate?.scrollViewOptionScrollNavigate(self, forward: steps > 0, amount: 1)
}

// MARK: - Pinch Zoom

/// 以 viewport 中心為中心的 Pinch Zoom
override func magnify(with event: NSEvent) {
    let point = zoomAnchorPoint()
    let newMag = magnification + event.magnification
    let effectiveMin = max(minMagnification, scrollDelegate?.minimumMagnification(for: self) ?? effectiveMinMagnification())
    setMagnificationPreservingInsets(
        max(effectiveMin, min(maxMagnification, newMag)),
        centeredAt: point
    )
    scrollDelegate?.scrollViewMagnificationDidChange(
        self,
        magnification: magnification,
        gesturePhase: event.phase
    )
}

private func setMagnificationPreservingInsets(_ magnification: CGFloat, centeredAt point: NSPoint) {

    applyCenteringInsetsIfNeeded(reason: "setMagnificationCentered")
}

private func effectiveWindowResizeMinMagnification() -> CGFloat {
    guard shouldResizeWindowToMatchImage(),
          !settings.continuousScrollEnabled,
          let imageSize = currentDocumentSize,
          imageSize.width > 0,
          imageSize.height > 0 else {
        return Constants.minMagnification
    }

    let fallbackMinContentSize = NSSize(
        width: Constants.minWindowContentWidth,
        height: Constants.minWindowContentHeight
    )
    let minContentSize = (view.window?.windowController as? ImageWindowController)?
        .effectiveMinimumContentSize() ?? fallbackMinContentSize
    let minViewportHeight = max(minContentSize.height - effectiveStatusBarHeight, 0)
    let minMagW = minContentSize.width / imageSize.width
    let minMagH = minViewportHeight / imageSize.height
    return max(Constants.minMagnification, max(minMagW, minMagH))
}

/// Delegates to scrollView's baseline minimum and upgrades it with the real window/content minimum.
private func effectiveMinMagnification() -> CGFloat {
    max(scrollView.effectiveMinMagnification(), effectiveWindowResizeMinMagnification())
}

